const row = items[0].json[0];
if (!row) throw new Error('No row returned for member_agreement_id');

if (!row.documenso_template_envelope_id) {
  throw new Error('Missing agreement_templates.documenso_template_envelope_id. Run db/migrations_documenso_integration.sql and seed the template row.');
}
if (!row.documenso_member_recipient_id || !row.documenso_facilitator_recipient_id) {
  throw new Error('Missing agreement_templates Documenso recipient IDs (member/facilitator).');
}
if (!row.member_email) throw new Error('Member email is required to send a Documenso request.');
if (!row.facilitator_email) throw new Error('Facilitator email is required to send a Documenso request.');

const externalId = `ma:${row.member_agreement_id}`;

const payloadObj = {
  envelopeId: row.documenso_template_envelope_id,
  distributeDocument: true,
  externalId,
  recipients: [
    {
      id: row.documenso_member_recipient_id,
      email: row.member_email,
      name: `${row.member_first_name ?? ''} ${row.member_last_name ?? ''}`.trim()
    },
    {
      id: row.documenso_facilitator_recipient_id,
      email: row.facilitator_email,
      name: `${row.facilitator_first_name ?? ''} ${row.facilitator_last_name ?? ''}`.trim()
    }
  ]
};

return [{
  json: {
    member_agreement_id: row.member_agreement_id,
    externalId,
    payload: JSON.stringify(payloadObj)
  }
}];

const res = items[0].json;

// Documenso responses vary by version; try common shapes.
const docId = res?.payload?.id ?? res?.id ?? res?.documentId ?? res?.data?.id;
if (!docId) {
  throw new Error(`Documenso /envelope/use response missing id. Response: ${JSON.stringify(res).slice(0,1200)}`);
}

return [{
  json: {
    member_agreement_id: $node['Build Documenso Payload'].json.member_agreement_id,
    documenso_document_id: docId,
    documenso_external_id: $node['Build Documenso Payload'].json.externalId
  }
}];
